using Avalonia;
using Avalonia.Media;
using VisualRelay.Domain;

namespace VisualRelay.App.ViewModels;

public sealed class TaskRowViewModel(RelayTaskItem task) : ViewModelBase
{
    private static IBrush ResolveBrush(string resourceKey) =>
        (Application.Current?.FindResource(resourceKey) as IBrush)
        ?? Brushes.Transparent;

    private static BoxShadows ResolveShadows(string resourceKey) =>
        Application.Current?.FindResource(resourceKey) is BoxShadows bs
            ? bs
            : BoxShadows.Parse("0 0 0 0 #00000000");

    private static IBrush SelectedBrush => _selectedBrush ??= ResolveBrush("SelectedBorderBrush");
    private static readonly IBrush? _selectedBrush;

    private static IBrush RunningBrush => _runningBrush ??= ResolveBrush("RunningBorderBrush");
    private static readonly IBrush? _runningBrush;

    private static IBrush ReviewBrush => _reviewBrush ??= ResolveBrush("WarningTextBrush");
    private static readonly IBrush? _reviewBrush;

    private static IBrush WaitingCardBrush => _waitingCardBrush ??= ResolveBrush("CardBgBrush");
    private static readonly IBrush? _waitingCardBrush;

    private static IBrush SelectedCardBrush => _selectedCardBrush ??= ResolveBrush("SelectedBgBrush");
    private static readonly IBrush? _selectedCardBrush;

    private static IBrush RunningCardBrush => _runningCardBrush ??= ResolveBrush("RunningBgBrush");
    private static readonly IBrush? _runningCardBrush;

    private static IBrush WaitingBorderBrush => _waitingBorderBrush ??= ResolveBrush("BorderCardBrush");
    private static readonly IBrush? _waitingBorderBrush;

    private static IBrush SelectedBorderBrush => _selectedBorderBrush ??= ResolveBrush("SelectedBorderBrush");
    private static readonly IBrush? _selectedBorderBrush;

    private static IBrush RunningBorderBrush => _runningBorderBrush ??= ResolveBrush("RunningBorderBrush");
    private static readonly IBrush? _runningBorderBrush;

    private static BoxShadows NoShadow => _noShadow ??= ResolveShadows("NoShadow");
    private static readonly BoxShadows? _noShadow;

    private static BoxShadows SelectedShadow => _selectedShadow ??= ResolveShadows("SelectedGlow22");
    private static readonly BoxShadows? _selectedShadow;

    private static BoxShadows RunningShadow => _runningShadow ??= ResolveShadows("RunningGlow22");
    private static readonly BoxShadows? _runningShadow;

    private bool _isSelected;
    private bool _isRunning;
    private bool _planned;
    private int? _runningStageNumber;
    private string? _runningStageName;
    private string? _planningLabel;
    private string _runningElapsedLabel = string.Empty;
    private string _rewriteElapsedLabel = string.Empty;

    public RelayTaskItem Task { get; internal set; } = task;
    public string Id => Task.Id;
    public string MarkdownPath => Task.MarkdownPath;
    public string ReviewReason => Task.ReviewReason ?? string.Empty;
    public bool NeedsReview => Task.NeedsReview;
    public bool IsArchived => Task.IsArchived;
    public IReadOnlyList<string> SiblingPaths => Task.SiblingPaths;
    public string DayHeader { get; set; } = string.Empty;
    public string StateLabel => IsRunning ? "Running" : Task.StateLabel;
    public string MetricsLine => IsRunning
        ? string.IsNullOrEmpty(_runningElapsedLabel)
            ? RunningStepLabel
            : $"{RunningStepLabel} · {_runningElapsedLabel}"
        : !string.IsNullOrEmpty(_rewriteElapsedLabel)
            ? $"Rewriting · {_rewriteElapsedLabel}"
            : Task.MetricsLine;
    public string RunningStepLabel => _runningStageNumber is { } number
        ? $"Stage {number:00} · {_runningStageName ?? "Running"}"
        : "Starting task";
    public string RunningElapsedLabel
    {
        get => _runningElapsedLabel;
        set
        {
            if (SetProperty(ref _runningElapsedLabel, value))
            {
                OnPropertyChanged(nameof(MetricsLine));
            }
        }
    }

    public string RewriteElapsedLabel
    {
        get => _rewriteElapsedLabel;
        set
        {
            if (SetProperty(ref _rewriteElapsedLabel, value))
            {
                OnPropertyChanged(nameof(MetricsLine));
            }
        }
    }
    public IBrush AccentBrush => IsRunning ? RunningBrush : NeedsReview ? ReviewBrush : SelectedBrush;
    public IBrush RailBrush => IsRunning ? RunningBrush : IsSelected ? SelectedBrush : Brushes.Transparent;
    public IBrush CardBackgroundBrush => IsRunning ? RunningCardBrush : IsSelected ? SelectedCardBrush : WaitingCardBrush;
    public IBrush BorderBrush => IsRunning ? RunningBorderBrush : IsSelected ? SelectedBorderBrush : WaitingBorderBrush;
    public Thickness CardBorderThickness => IsRunning || IsSelected ? new Thickness(2) : new Thickness(1);
    public BoxShadows CardShadow => IsRunning ? RunningShadow : IsSelected ? SelectedShadow : NoShadow;
    public double ProgressFraction => Math.Clamp(Task.CompletedStageCount / 11.0, 0, 1);

    public bool IsSelected
    {
        get => _isSelected;
        set
        {
            if (SetProperty(ref _isSelected, value))
            {
                NotifyVisualStateChanged();
            }
        }
    }

    public bool IsRunning
    {
        get => _isRunning;
        private set
        {
            if (SetProperty(ref _isRunning, value))
            {
                OnPropertyChanged(nameof(StateLabel));
                OnPropertyChanged(nameof(MetricsLine));
                NotifyVisualStateChanged();
            }
        }
    }

    public void MarkRunning(int? stageNumber = null, string? stageName = null)
    {
        _runningStageNumber = stageNumber;
        _runningStageName = stageName;
        _planningLabel = null;
        IsRunning = true;
        OnPropertyChanged(nameof(RunningStepLabel));
        OnPropertyChanged(nameof(MetricsLine));
        OnPropertyChanged(nameof(PhaseLabel));
    }

    public void MarkPlanning()
    {
        _runningStageNumber = null;
        _runningStageName = null;
        _planningLabel = "Planning…";
        IsRunning = true;
        OnPropertyChanged(nameof(RunningStepLabel));
        OnPropertyChanged(nameof(MetricsLine));
        OnPropertyChanged(nameof(PhaseLabel));
    }

    public void MarkPlanned()
    {
        _runningStageNumber = null;
        _runningStageName = null;
        _planningLabel = null;
        _planned = true;
        IsRunning = false;
        OnPropertyChanged(nameof(StateLabel));
        OnPropertyChanged(nameof(MetricsLine));
        OnPropertyChanged(nameof(PhaseLabel));
    }

    public void MarkIdle()
    {
        _runningStageNumber = null;
        _runningStageName = null;
        _runningElapsedLabel = string.Empty;
        _rewriteElapsedLabel = string.Empty;
        _planningLabel = null;
        _planned = false;
        IsRunning = false;
        OnPropertyChanged(nameof(RunningStepLabel));
        OnPropertyChanged(nameof(RunningElapsedLabel));
        OnPropertyChanged(nameof(RewriteElapsedLabel));
        OnPropertyChanged(nameof(MetricsLine));
        OnPropertyChanged(nameof(PhaseLabel));
    }

    public string PhaseLabel => _planningLabel ?? (_planned ? "Planned · queued" : string.Empty);

    private void NotifyVisualStateChanged()
    {
        OnPropertyChanged(nameof(AccentBrush));
        OnPropertyChanged(nameof(RailBrush));
        OnPropertyChanged(nameof(CardBackgroundBrush));
        OnPropertyChanged(nameof(BorderBrush));
        OnPropertyChanged(nameof(CardBorderThickness));
        OnPropertyChanged(nameof(CardShadow));
    }
}

