[AvaloniaFact]
public void ChevronForeground_HasExplicitDefault_NotNull()
{
    var icon = new ChevronIcon();
    // The value is null before styling; apply Avalonia styles to resolve it.
    var window = CreateWindow();
    window.Show();
    // Apply the theme style to resolve the Foreground
    App.ApplyStyles(icon);
    Assert.NotNull(icon.Foreground);
    window.Close();
}

